async def scrape(engine: CrawlEngineHandle, url: str) -> ScrapeResult:
    """Scrape a single URL, returning extracted page data."""
    return await _rust.scrape(engine=engine, url=url)


async def crawl(engine: CrawlEngineHandle, url: str) -> CrawlResult:
    """Crawl a website starting from `url`, following links up to the configured depth."""
    return await _rust.crawl(engine=engine, url=url)


async def map_urls(engine: CrawlEngineHandle, url: str) -> MapResult:
    """Discover all pages on a website by following links and sitemaps."""
    return await _rust.map_urls(engine=engine, url=url)


async def interact(
    engine: CrawlEngineHandle,
    url: str,
    actions: list[PageAction],
) -> InteractionResult:
    """Execute browser actions on a single page."""
    _rust_actions = [
        (_rust.PageAction(__item) if not isinstance(__item, _rust.PageAction) else __item) for __item in actions
    ]

    return await _rust.interact(engine=engine, url=url, actions=_rust_actions)


async def batch_scrape(engine: CrawlEngineHandle, urls: list[str]) -> BatchScrapeResults:
    """Scrape multiple URLs concurrently."""
    return await _rust.batch_scrape(engine=engine, urls=urls)


async def batch_crawl(engine: CrawlEngineHandle, urls: list[str]) -> BatchCrawlResults:
    """Crawl multiple seed URLs concurrently, each following links to configured depth."""
